const body = $json.body || {};
const raw = body.message?.content ?? body.message ?? '';
const message = typeof raw === 'string' ? raw.trim() : String(raw ?? '').trim();
if (!message) throw new Error('message.content es obligatorio');
if (message.length > 6000) throw new Error('Mensaje demasiado largo');
return { json: {
  session_id: String(body.session?.id || body.conversation_id || $execution.id),
  conversation_id: String(body.conversation_id || body.session?.id || ''),
  user_id: String(body.user_id || ''),
  message,
  channel: body.channel || 'web',
  locale: body.locale || 'es-EC'
} };

const input = $('Normalizar Entrada').first().json;
const normalized = input.message.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const patterns = [
  ['dificultad respiratoria', /dificultad para respirar|no puede respirar|me falta el aire/],
  ['dolor fuerte en el pecho', /dolor (muy )?fuerte en el pecho/],
  ['pérdida de conciencia', /perdio el conocimiento|esta inconsciente|no responde/],
  ['convulsión', /convulsion|convulsionando/],
  ['sangrado abundante', /sangrado abundante|no para de sangrar/],
  ['riesgo de autolesión', /se quiere matar|intento de suicidio|hacerme dano|hacerme daño/]
];
const warnings = patterns.filter(([, regex]) => regex.test(normalized)).map(([label]) => label);
const vulnerable = /embaraz|bebe|reci[eé]n nacido|adulto mayor|diabetes|hipertension/.test(normalized);
return { json: {
  emergency_detected: warnings.length > 0,
  warning_signs: warnings,
  minimum_priority: warnings.length ? 'EMERGENCY' : null,
  vulnerable_context: vulnerable
} };

