function parseNode(name) {
  try {
    const raw = $(name).first().json;
    const text = raw.output?.[0]?.content?.[0]?.text ?? raw.text ?? raw;
    if (typeof text === 'object') return text;
    return JSON.parse(String(text).replace(/```json/gi, '').replace(/```/g, '').trim());
  } catch { return {}; }
}
const general = parseNode('Asistente General de Salud');
const triage = parseNode('Agente de Clasificación y Acceso');
const serviceSelection = parseNode('Agente de Acceso a Servicios');
const prevention = parseNode('Agente de Prevención y Trámites');
const safety = $('Reglas Determinísticas').first().json;
const input = $('Normalizar Entrada').first().json;
const healthCase = { ...triage, ...(general.case || {}) };
healthCase.reason = healthCase.reason || input.message.slice(0, 180);
healthCase.reported_symptoms = Array.isArray(healthCase.reported_symptoms) ? healthCase.reported_symptoms : [];
healthCase.relevant_conditions = Array.isArray(healthCase.relevant_conditions) ? healthCase.relevant_conditions : [];
healthCase.accessibility_needs = Array.isArray(healthCase.accessibility_needs) ? healthCase.accessibility_needs : [];
healthCase.access_barriers = Array.isArray(healthCase.access_barriers) ? healthCase.access_barriers : [];
healthCase.warning_signs = [...new Set([...(Array.isArray(healthCase.warning_signs) ? healthCase.warning_signs : []), ...(safety.warning_signs || [])])];
if (safety.emergency_detected) {
  healthCase.priority_level = 'EMERGENCY';
  healthCase.priority_score = Math.max(Number(healthCase.priority_score || 0), 95);
  healthCase.status = 'PENDING_REVIEW';
  healthCase.requires_human_review = true;
}
let reply = String(general.reply || '').trim();
if (!reply) reply = 'Puedo ayudarte a organizar tu necesidad y encontrar un servicio. ¿En qué sector de Manta te encuentras?';
if (safety.emergency_detected && !/911|atenci[oó]n inmediata|emergencia/i.test(reply)) {
  reply = 'Los síntomas descritos pueden requerir atención inmediata. Busca ayuda ahora o llama al ECU 911. No esperes una nueva respuesta del sistema. ' + reply;
}
const services = Array.isArray(general.services) && general.services.length ? general.services : (Array.isArray(serviceSelection.services) ? serviceSelection.services : []);
const sources = Array.isArray(general.sources) && general.sources.length ? general.sources : (Array.isArray(prevention.sources) ? prevention.sources : []);
const followUp = general.follow_up || { required: ['EMERGENCY','PRIORITY'].includes(healthCase.priority_level), suggested_time: healthCase.priority_level === 'EMERGENCY' ? 'inmediato' : '24 horas', action: 'confirm_attention' };
return { json: {
  reply,
  case: healthCase,
  services,
  sources,
  follow_up: followUp,
  ui: {
    show_emergency_banner: safety.emergency_detected || healthCase.priority_level === 'EMERGENCY',
    show_services: services.length > 0,
    show_human_review: Boolean(healthCase.requires_human_review)
  },
  agent: 'GPT-5.6 Sol',
  trace: { intent: parseNode('Orquestador').intent || 'OTHER', deterministic_safety: safety }
} };

