SELECT cf.id, cf.case_id, cf.case_summary, cf.access_barriers, cf.case_status, cf.suggested_action,
 cf.action_details, cf.scheduled_at AS follow_up_at, cf.requires_review AS requires_human_review, cf.created_at
FROM case_followups cf WHERE cf.status='pending' ORDER BY cf.requires_review DESC, cf.scheduled_at ASC NULLS LAST;

